// // This module implements a synchronous reset D flip-flop.
module d_ff_async_reset (
    input clk,
    input rst,
    input d,
    output reg q
);

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            q <= 1'b0;
        end else begin
            q <= d;
        end
    end
endmodule
